function StatsCard({ title, value, trend, trendValue, icon: Icon, colorClass }) {
    const isPositive = trend === 'up';

    return (
        <div className="bg-white p-6 rounded-xl border border-[#e2e8f0] flex flex-col hover:shadow-sm transition-shadow">
            <div className="flex justify-between items-start mb-4">
                <div className={`p-3 rounded-lg ${colorClass}`}>
                    <Icon className="w-6 h-6" />
                </div>
                <div className={`flex items-center gap-1 text-sm font-medium ${isPositive ? 'text-green-600' : 'text-red-600'}`}>
                    {isPositive ? '+' : '-'}{trendValue}%
                </div>
            </div>
            <div>
                <h3 className="text-[#64748b] text-sm font-medium mb-1">{title}</h3>
                <p className="text-2xl font-bold text-[#1e293b]">{value}</p>
            </div>
        </div>
    );
}

export default StatsCard;

import { NavLink, useLocation } from 'react-router-dom';
import { LayoutDashboard, Briefcase, FileUp, Users } from 'lucide-react';

function Sidebar() {
    const location = useLocation();

    const navItems = [
        { path: '/', label: 'Dashboard', icon: LayoutDashboard },
        { path: '/job', label: 'Job Description', icon: Briefcase },
        { path: '/upload', label: 'Resume Upload', icon: FileUp },
        { path: '/results', label: 'Candidate Rankings', icon: Users },
    ];

    return (
        <aside className="w-64 bg-white border-r border-[#e2e8f0] hidden md:flex flex-col">
            <div className="p-6 border-b border-[#e2e8f0]">
                <h1 className="text-xl font-bold text-[#1e293b]">Recruit<span className="text-[#3b82f6]">AI</span></h1>
            </div>
            <nav className="flex-1 overflow-y-auto py-4">
                <ul className="space-y-1 px-3">
                    {navItems.map((item) => {
                        const Icon = item.icon;
                        const isActive = location.pathname === item.path || (item.path !== '/' && location.pathname.startsWith(item.path));

                        return (
                            <li key={item.path}>
                                <NavLink
                                    to={item.path}
                                    className={({ isActive }) => `flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-colors cursor-pointer ${isActive
                                            ? 'bg-[#eff6ff] text-[#2563eb]'
                                            : 'text-[#64748b] hover:bg-[#f8fafc] hover:text-[#1e293b]'
                                        }`}
                                >
                                    <Icon className="w-5 h-5" />
                                    {item.label}
                                </NavLink>
                            </li>
                        );
                    })}
                </ul>
            </nav>
            <div className="p-4 border-t border-[#e2e8f0]">
                <div className="flex items-center gap-3 px-2">
                    <div className="w-8 h-8 rounded-full bg-[#e2e8f0] flex items-center justify-center text-[#64748b] font-medium text-sm">
                        HR
                    </div>
                    <div className="flex-1 min-w-0">
                        <p className="text-sm font-medium text-[#1e293b] truncate">HR Manager</p>
                        <p className="text-xs text-[#64748b] truncate">Enterprise Plan</p>
                    </div>
                </div>
            </div>
        </aside>
    );
}

export default Sidebar;

